mapper.select:
SELECT * FROM user_post_behavior 
WHERE user_id = #{userId} 
ORDER BY behavior_time DESC

SELECT * FROM user_post_behavior 
WHERE post_id = #{postId} 
ORDER BY behavior_time DESC

SELECT upb.* FROM user_post_behavior upb
WHERE upb.post_id IN (
    SELECT post_id FROM user_post_behavior 
    WHERE user_id = #{userId} AND behavior_type = #{behaviorType}
)
AND upb.user_id != #{userId}
AND upb.behavior_type = #{behaviorType}
